import React, { useState } from 'react';
import DrawerMenu from '../components/DrawerMenu';
import Header from '../components/Header';

function TeamMatching1() {
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [openMenus, setOpenMenus] = useState({});

  return (
    <div style={{ fontFamily: "'Montserrat', 'Noto Sans KR', sans-serif", minHeight: '100vh', background: '#f8f9fc' }}>
      <Header onMenuOpen={() => setDrawerOpen(true)} />
      <DrawerMenu open={drawerOpen} onClose={() => setDrawerOpen(false)} openMenus={openMenus} onToggle={setOpenMenus} />

      {/* 설명 텍스트 */}
      <div style={{ marginTop: '4.5rem', padding: '2rem 3rem' }}>
        <h1 style={{ color: '#FF6B35', fontSize: '2.2rem', fontWeight: 800 }}>
          AutoTeamUp - 빠르게 팀 결성하기
        </h1>
        <p style={{ fontSize: '1.1rem', color: '#555', marginTop: '0.7rem' }}>
          공모전을 선택한 참가자들이 랜덤으로 팀을 결성한 후, <b>2차 피드백</b>을 통해 최종 팀을 확정하는 방식입니다.
        </p>
      </div>

      {/* 이후 매칭 기능 영역 추가 예정 */}
    </div>
  );
}

export default TeamMatching1;
